    {
        _profileService = profileService;
        _connectionService = connectionService;
        _binaryManager = binaryManager;
        _parserFactory = parserFactory;
        _logger = logger;

        _connectionService.StateChanged += OnConnectionStateChanged;
        _connectionService.LogReceived += OnLogReceived;
    }

    public event Action? RequestMinimizeToTray;

    public Task InitializeAsync()
    {
        if (!EnsureDisclaimerAccepted())
        {
            Application.Current.Shutdown();
            return Task.CompletedTask;
        }

        Profiles.Clear();
        foreach (var profile in _profileService.Profiles)
            Profiles.Add(profile);

        ConnectionState = _connectionService.State;
        AppendLog("Application started.");
        return Task.CompletedTask;
    }

    private static bool EnsureDisclaimerAccepted()
    {
        if (File.Exists(Constants.DisclaimerFlagFile))
            return true;

        var result = MessageBox.Show(
            DisclaimerText,
            "Legal Disclaimer",
            MessageBoxButton.YesNo,
            MessageBoxImage.Information);

        if (result != MessageBoxResult.Yes)
            return false;

        try
        {
            Constants.EnsureDirectories();
            File.WriteAllText(Constants.DisclaimerFlagFile, DateTimeOffset.UtcNow.ToString("O"));
        }
        catch
        {
            // Non-fatal; user accepted in-session.
        }

        return true;
    }

    [RelayCommand]
    private async Task ImportFileAsync()
    {
        var dialog = new OpenFileDialog
        {
            Title = "Import configuration file",
            Filter = "Napsternet configs|*.npvt;*.npv4;*.npv;*.npv2|All files|*.*",
            Multiselect = false
        };

        if (dialog.ShowDialog() != true)
            return;

        await ImportFilePathAsync(dialog.FileName);
    }

    [RelayCommand]
    private async Task ImportUriAsync()
    {
        var uri = InputDialog.Prompt(
            Application.Current.MainWindow,
            "Import URI",
            "Paste one or more share links (vmess://, vless://, trojan://, ss://):");

        if (string.IsNullOrWhiteSpace(uri))
            return;

        await ImportUriContentAsync(uri.Trim());
    }

    [RelayCommand(CanExecute = nameof(CanConnect))]
    private async Task ConnectAsync()
    {
        if (SelectedProfile is null)
            return;

        if (SelectedMode == ConnectionMode.Tun && !ElevationHelper.IsRunningAsAdmin())
        {
            var answer = MessageBox.Show(
                "TUN mode requires administrator privileges.\n\nRestart NapsternetV Client as administrator?",
                "Elevation Required",
                MessageBoxButton.YesNo,
                MessageBoxImage.Warning);

            if (answer == MessageBoxResult.Yes && ElevationHelper.TryRestartAsAdmin())
                Application.Current.Shutdown();

            return;
        }

        try
        {
            IsBusy = true;
            StatusMessage = "Preparing binaries…";
            AppendLog("Ensuring core binaries are available…");

            await _binaryManager.EnsureAllAsync(new Progress<string>(AppendLog));

            StatusMessage = "Connecting…";
            AppendLog($"Connecting to {SelectedProfile.Name} ({SelectedMode})…");

            await _connectionService.ConnectAsync(SelectedProfile, SelectedMode);
            StatusMessage = "Connected";
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Connect failed");
            AppendLog($"Connect failed: {ex.Message}");
            StatusMessage = "Connection failed";
            MessageBox.Show(ex.Message, "Connection Error", MessageBoxButton.OK, MessageBoxImage.Error);
        }
        finally
        {
            IsBusy = false;
            ConnectCommand.NotifyCanExecuteChanged();
            DisconnectCommand.NotifyCanExecuteChanged();
        }
    }

    private bool CanConnect =>
        !IsBusy &&
        SelectedProfile is not null &&
        ConnectionState is ConnectionState.Disconnected or ConnectionState.Error;

    [RelayCommand(CanExecute = nameof(CanDisconnect))]
    private async Task DisconnectAsync()
    {
        try
        {
            IsBusy = true;
            StatusMessage = "Disconnecting…";
            AppendLog("Disconnecting…");
            await _connectionService.DisconnectAsync();
            StatusMessage = "Disconnected";
            AppendLog("Disconnected.");
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Disconnect failed");
            AppendLog($"Disconnect failed: {ex.Message}");
            StatusMessage = "Disconnect failed";
        }
        finally
        {
            IsBusy = false;
            ConnectCommand.NotifyCanExecuteChanged();
            DisconnectCommand.NotifyCanExecuteChanged();
        }
    }

    private bool CanDisconnect =>
        !IsBusy &&
        ConnectionState is ConnectionState.Connected or ConnectionState.Connecting;

    [RelayCommand]
    private void RemoveProfile()
    {
        if (SelectedProfile is null)
            return;

        var profile = SelectedProfile;
        if (MessageBox.Show(
                $"Remove profile \"{profile.Name}\"?",
                "Remove Profile",
                MessageBoxButton.YesNo,
                MessageBoxImage.Question) != MessageBoxResult.Yes)
            return;

        _profileService.Remove(profile.Id);
        Profiles.Remove(profile);
        SelectedProfile = Profiles.FirstOrDefault();
        AppendLog($"Removed profile: {profile.Name}");
    }

    [RelayCommand]
    private void ClearLog() => LogLines.Clear();

    public void MinimizeToTray() => RequestMinimizeToTray?.Invoke();

    public async Task DisconnectOnExitAsync()
    {
        if (ConnectionState is ConnectionState.Connected or ConnectionState.Connecting)
        {
            try
            {
                await _connectionService.DisconnectAsync();
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Disconnect on exit failed");
            }
        }
    }

    partial void OnSelectedProfileChanged(ServerProfile? value) =>
        ConnectCommand.NotifyCanExecuteChanged();

    partial void OnConnectionStateChanged(ConnectionState value)
    {
        ConnectCommand.NotifyCanExecuteChanged();
        DisconnectCommand.NotifyCanExecuteChanged();
    }

    partial void OnIsBusyChanged(bool value)
    {
        ConnectCommand.NotifyCanExecuteChanged();
        DisconnectCommand.NotifyCanExecuteChanged();
    }

    private async Task ImportFilePathAsync(string filePath)
    {
        string extension = Path.GetExtension(filePath).ToLowerInvariant();
        string? password = null;

        if (extension == ".npvt")
        {
            try
            {
                IsBusy = true;
                StatusMessage = "Downloading npvt-decoder…";
                AppendLog("Ensuring npvt-decoder is available…");
                await _binaryManager.EnsureNpvtDecoderAsync(new Progress<string>(AppendLog));
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Failed to ensure npvt-decoder");
                AppendLog($"Failed to download npvt-decoder: {ex.Message}");
                MessageBox.Show(ex.Message, "Import Error", MessageBoxButton.OK, MessageBoxImage.Error);
                return;
            }
            finally
            {
                IsBusy = false;
            }
        }

        for (int attempt = 0; attempt < 2; attempt++)
        {
            try
            {
                IsBusy = true;
                StatusMessage = "Importing…";
                AppendLog($"Importing {Path.GetFileName(filePath)}…");

                var imported = await _parserFactory.ImportFileAsync(filePath, password);
                AddImportedProfiles(imported);
                StatusMessage = $"Imported {imported.Count} profile(s)";
                return;
            }
            catch (Exception ex) when (attempt == 0 && RequiresPassword(ex))
            {
                password = PasswordDialog.Prompt(
                    Application.Current.MainWindow,
                    "Password Required",
                    "This configuration is encrypted. Enter the password:");

                if (string.IsNullOrEmpty(password))
                {
                    AppendLog("Import cancelled — password required.");
                    StatusMessage = "Import cancelled";
                    return;
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Import failed for {File}", filePath);
                AppendLog($"Import failed: {ex.Message}");
                StatusMessage = "Import failed";
                MessageBox.Show(ex.Message, "Import Error", MessageBoxButton.OK, MessageBoxImage.Error);
                return;
            }
            finally
            {
                IsBusy = false;
            }
        }
    }

    private async Task ImportUriContentAsync(string content)
    {
        try
        {
            IsBusy = true;
            StatusMessage = "Importing URI…";
            AppendLog("Importing share link…");

            var imported = await _parserFactory.ParseAsync(content);
            AddImportedProfiles(imported);
            StatusMessage = $"Imported {imported.Count} profile(s)";
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "URI import failed");
            AppendLog($"Import failed: {ex.Message}");
            StatusMessage = "Import failed";
            MessageBox.Show(ex.Message, "Import Error", MessageBoxButton.OK, MessageBoxImage.Error);
        }
        finally
        {
            IsBusy = false;
        }
    }

    private void AddImportedProfiles(IReadOnlyList<ServerProfile> imported)
    {
        foreach (var profile in imported)
        {
            _profileService.Add(profile);
            Profiles.Add(profile);
        }

        if (imported.Count > 0)
        {
            SelectedProfile = imported[0];
            AppendLog($"Imported: {imported[0].Name}");
        }
    }

    private static bool RequiresPassword(Exception ex) =>
        ex.Message.Contains("password", StringComparison.OrdinalIgnoreCase);

    private void OnConnectionStateChanged(object? sender, ConnectionState state)
    {
        Application.Current.Dispatcher.Invoke(() =>
        {
            ConnectionState = state;
            StatusMessage = state.ToString();
        });
    }

    private void OnLogReceived(object? sender, string line) =>
        Application.Current.Dispatcher.Invoke(() => AppendLog(line));

    private void AppendLog(string line)
    {
        string redacted = LogRedactor.Redact(line);
        LogLines.Add($"[{DateTime.Now:HH:mm:ss}] {redacted}");

        while (LogLines.Count > MaxLogLines)
            LogLines.RemoveAt(0);
    }

    public void Dispose()
    {
        _connectionService.StateChanged -= OnConnectionStateChanged;
        _connectionService.LogReceived -= OnLogReceived;
    }
}

