using System.Collections.Specialized;
using System.ComponentModel;
using System.Windows;
using Hardcodet.Wpf.TaskbarNotification;
using NapsternetVClient.ViewModels;

namespace NapsternetVClient.Views;

public partial class MainWindow : Window
{
    private readonly MainViewModel _viewModel;
    private bool _isExiting;

    public MainWindow(MainViewModel viewModel)
    {
        InitializeComponent();
        _viewModel = viewModel;
        DataContext = viewModel;

        viewModel.RequestMinimizeToTray += HideToTray;
        viewModel.LogLines.CollectionChanged += LogLines_CollectionChanged;

        Closed += (_, _) => viewModel.LogLines.CollectionChanged -= LogLines_CollectionChanged;
    }

    private void LogLines_CollectionChanged(object? sender, NotifyCollectionChangedEventArgs e)
    {
        if (e.Action == NotifyCollectionChangedAction.Add && LogListBox.Items.Count > 0)
        {
            LogListBox.ScrollIntoView(LogListBox.Items[^1]);
        }
    }

    private void Window_StateChanged(object sender, EventArgs e)
    {
        if (WindowState == WindowState.Minimized && _viewModel.MinimizeToTrayOnClose)
            HideToTray();
    }

    private void Window_Closing(object? sender, CancelEventArgs e)
    {
        if (_isExiting)
            return;

        if (_viewModel.MinimizeToTrayOnClose)
        {
            e.Cancel = true;
            HideToTray();
        }
    }

    private void HideToTray()
    {
        Hide();
        TrayIcon.Visibility = Visibility.Visible;
        ShowInTaskbar = false;
    }

    private void ShowFromTray()
    {
        TrayIcon.Visibility = Visibility.Collapsed;
        ShowInTaskbar = true;
        Show();
        WindowState = WindowState.Normal;
        Activate();
    }

    private void TrayIcon_TrayMouseDoubleClick(object sender, RoutedEventArgs e) => ShowFromTray();

    private void TrayShow_Click(object sender, RoutedEventArgs e) => ShowFromTray();

    private void TrayExit_Click(object sender, RoutedEventArgs e)
    {
        _isExiting = true;
        Application.Current.Shutdown();
    }

    public void PrepareForExit() => _isExiting = true;
}

using System.Windows;
using Microsoft.Extensions.Logging;
using NapsternetVClient.Core;
using NapsternetVClient.Parsers;
using NapsternetVClient.Services;
using NapsternetVClient.ViewModels;
using NapsternetVClient.Views;

namespace NapsternetVClient;

public partial class App : Application
{
    private ILoggerFactory? _loggerFactory;
    private ConnectionService? _connectionService;
    private MainViewModel? _mainViewModel;
    private MainWindow? _mainWindow;

    protected override async void OnStartup(StartupEventArgs e)
    {
        base.OnStartup(e);

        _loggerFactory = LoggerFactory.Create(builder =>
        {
            builder.AddDebug();
            builder.SetMinimumLevel(LogLevel.Information);
        });

        var logger = _loggerFactory.CreateLogger<App>();
        logger.LogInformation("NapsternetV Client starting");

        var connectionService = new ConnectionService(_loggerFactory.CreateLogger<ConnectionService>());
        _connectionService = connectionService;
        connectionService.RecoverDirtySession();

        var profileService = new ProfileService(_loggerFactory.CreateLogger<ProfileService>());
        var binaryManager = new BinaryManager(_loggerFactory.CreateLogger<BinaryManager>());
        var parserFactory = new ParserFactory(_loggerFactory);

        _mainViewModel = new MainViewModel(
            profileService,
            connectionService,
            binaryManager,
            parserFactory,
            _loggerFactory.CreateLogger<MainViewModel>());

        _mainWindow = new MainWindow(_mainViewModel);
        MainWindow = _mainWindow;

        await _mainViewModel.InitializeAsync();
        if (Current.MainWindow is null)
            return;

        _mainWindow.Show();

        SessionEnding += OnSessionEnding;
    }

    private async void OnSessionEnding(object sender, SessionEndingCancelEventArgs e)
    {
        await CleanupAsync();
    }

    protected override async void OnExit(ExitEventArgs e)
    {
        await CleanupAsync();
        _loggerFactory?.Dispose();
        base.OnExit(e);
    }

    private async Task CleanupAsync()
    {
        if (_mainWindow is not null)
            _mainWindow.PrepareForExit();

        if (_mainViewModel is not null)
            await _mainViewModel.DisconnectOnExitAsync();

        _mainViewModel?.Dispose();
        _connectionService?.Dispose();
    }
}

